library(tidyverse)
library(tidylog)

source("code/functions.R")

icpsr_jails_prisons <-
  arrow::read_feather("data/jails_prisons.feather") |>
  distinct(bjs_facility_ID, name, state) |>
  mutate(name_join = clean_text(name))

hifld_lef <-
  arrow::read_feather("data/hifld-local-law-enforcement-facilities.feather") |>
  # filter(str_detect(type, "Jail|Prison")) |>
  mutate(name_join = clean_text(name)) |>
  select(hifld_id, name, state, name_join)

hifld_prisons <-
  arrow::read_feather("data/hifld-prisons.feather") |>
  mutate(name_join = clean_text(name)) |>
  select(hifld_id, name, state, name_join)

jail_prison_list <-
  bind_rows(
    "icpsr" = icpsr_jails_prisons |>
      select(id = bjs_facility_ID, name, state, name_join),
    "hifld_lef" = hifld_lef |> select(id = hifld_id, name, state, name_join),
    "hifld_prisons" = hifld_prisons |>
      select(id = hifld_id, name, state, name_join),
    .id = "source"
  )

name_state_match <- arrow::read_feather(
  "data/facilities-name-state-match.feather"
)

# select places that are not
facilities_from_detentions <-
  arrow::read_feather(
    "data/facilities-from-detentions.feather"
  ) |>
  mutate(name_join = clean_text(detention_facility)) |>
  filter(
    !str_detect(
      name_join,
      "hosp|medicine|\\bnurs\\b|nursing|medical|\\bmed\\b|health|clinic|emerg|kaiser|hca|surgic|surger|orthop|spine|shriners|transplant|hlth|mayo|infirmary|wellness|physician|ambulatory|\\beye\\b|medstar"
    ) &
      !name_join %in% c("samaritan behavioral center", "Scan inc")
  ) |>
  select(detention_facility_code, name = detention_facility, name_join) |>
  left_join(
    name_state_match |> select(detention_facility_code, state),
    by = c("detention_facility_code")
  )

