matches_cleaned <- read_rds("~/downloads/matches-jails-prisons.rds")

matches_cleaned |>
  as_tibble() |>
  filter(match == "Yes", match_probability >= 0.75) |>
  select(name.x, name.y, state) |>
  arrange(state, name.x) |>
  clipr::write_clip()

